export default function FinalResults({ results }) {
  const location = useLocation();

  const [user, setUser] = useState(false);
  const [saved, setSaved] = useState(false);
  const [articles, setArticles] = useState([]);

  const queryType = new URLSearchParams(location.search).get("type");

  const type =
    queryType ||
    (results?.EI || "") +
    (results?.SN || "") +
    (results?.TF || "") +
    (results?.JP || "");

  useEffect(() => {
    const token = localStorage.getItem("auth_token");
    if (token) setUser(true);

    const savedResult = localStorage.getItem("savedResult");
    if (savedResult) setSaved(true);
  }, []);

  useEffect(() => {
    if (!type) return;

    fetch(`http://localhost:5000/api/articles?q=${type}`)
      .then(res => res.json())
      .then(data => setArticles(data.slice(0, 4)))
      .catch(() => {});
  }, [type]);

  const toggleSave = () => {
    if (saved) {
      localStorage.removeItem("savedResult");
      setSaved(false);
    } else {
      localStorage.setItem("savedResult", type);
      setSaved(true);
    }
  };

  return (
    <div className="test-card" style={{ position: "relative" }}>
      {user && (
        <img
          src={saved ? "/save1.png" : "/save.png"}
          className="save-icon-result"
          onClick={toggleSave}
          alt="save"
        />
      )}

      <img className="result-image" src={`/images/types/${type}.png`} alt={type} />

      <p className="test-description">
        {typeDescriptions[type] || "ეს არის მოკლე აღწერა თქვენს ფსიქოტიპზე."}
      </p>

      {!user && (
        <p className="register-text">
          მონაცემების შესანახად{" "}
          <Link
            to="/register"
            className="register-link"
            onClick={() => localStorage.setItem("pendingResult", type)}
          >
            გაიარე რეგისტრაცია
          </Link>
        </p>
      )}

      {/* ✅ შესაბამისი სტატიები */}
      {articles.length > 0 && (
        <div className="related-articles">
          <h3>სტატიები შენთვის</h3>

          <div className="articles-row">
            {articles.map(article => (
              <Link
                key={article.slug}
                to={`/articles/${article.slug}`}
                className="article-card-mini"
              >
                <img
                  src={`http://localhost:5000${article.image}`}
                  alt={article.title}
                />
                <p>{article.title}</p>
              </Link>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
